import torch, re, sys
sys.path.insert(0, 'insight')
ckpt = torch.load('insight/checkpoints/epoch_070.pt', map_location='cpu', weights_only=True)
print('Keys:', list(ckpt.keys()))
print('Epoch:', ckpt.get('epoch'))
print('Val loss:', ckpt.get('val_loss'))
print('Stage:', ckpt.get('stage', 'N/A'))
sd = ckpt['model_state_dict']

stack_max_block = {}
for k in sd:
    m = re.match(r'encoder\.stacks\.(\d+)\.blocks\.(\d+)\.', k)
    if m:
        s, b = int(m.group(1)), int(m.group(2))
        stack_max_block[s] = max(stack_max_block.get(s, -1), b)
print(f'num_stacks={len(stack_max_block)}, num_blocks={max(stack_max_block.values())+1}')

for k in ['encoder.input_proj.weight', 'encoder.input_proj.bias']:
    if k in sd:
        print(f'{k}: {sd[k].shape}')

# param_head keys
for k in sorted(sd):
    if 'param_head' in k or 'head' in k:
        print(f'{k}: {sd[k].shape}')

# kernel size from conv
for k in sd:
    if 'filter_conv.conv.weight' in k:
        print(f'kernel_size from {k}: {sd[k].shape[-1]}')
        break
